def _drop_index_if_exists(cur, conn, table_name, index_name):
    """Drop index on table only if it exists. Handles MySQL and SQLite."""
    if conn.vendor == 'sqlite':
        cur.execute(
            "SELECT 1 FROM sqlite_master WHERE type='index' AND name=?",
            [index_name],
        )
        if cur.fetchone():
            cur.execute(f'DROP INDEX "{index_name}"')
    else:
        cur.execute(
            """
            SELECT 1 FROM information_schema.statistics
            WHERE table_schema = DATABASE() AND table_name = %s AND index_name = %s
            """,
            [table_name, index_name],
        )
        if cur.fetchone():
            cur.execute(f'ALTER TABLE `{table_name}` DROP INDEX `{index_name}`')


